class Solution {
    public String maximumBinaryString(String binary) {
        int countZero = 0, firstZeroIndex = -1;
        char[] chars = binary.toCharArray();
        for (int i = 0; i < chars.length; i++) {
            if (chars[i] == '0') {
                countZero++;
                if (firstZeroIndex == -1) {
                    firstZeroIndex = i;
                }
            }
        }
        if (countZero == 0) {
            return binary;
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < chars.length; i++) {
            if (i < firstZeroIndex) {
                sb.append('1');
            } else if (i >= firstZeroIndex && i < firstZeroIndex + countZero - 1) {
                sb.append('1');
            } else if (i == firstZeroIndex + countZero - 1) {
                sb.append('0');
            } else if (i > firstZeroIndex + countZero - 1) {
                sb.append(chars[i]);
            }
        }
        return sb.toString();
    }
}
